import{_ as a,c as o,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Início Rápido com AI App Factory: Da Instalação à Execução do Primeiro Aplicativo | agent-app-factory","description":"Aprenda como iniciar rapidamente o AI App Factory, desde a instalação e configuração da ferramenta CLI até entender como funciona o pipeline de 7 estágios. Este capítulo inclui quatro cursos essenciais: início rápido, instalação e configuração, inicialização de projeto e visão geral do pipeline, ajudando você a compreender completamente o fluxo de automação de ponta a ponta, da ideia ao aplicativo executável.","frontmatter":{"title":"Início Rápido com AI App Factory: Da Instalação à Execução do Primeiro Aplicativo | agent-app-factory","sidebarTitle":"Primeiros Passos","subtitle":"Primeiros Passos","description":"Aprenda como iniciar rapidamente o AI App Factory, desde a instalação e configuração da ferramenta CLI até entender como funciona o pipeline de 7 estágios. Este capítulo inclui quatro cursos essenciais: início rápido, instalação e configuração, inicialização de projeto e visão geral do pipeline, ajudando você a compreender completamente o fluxo de automação de ponta a ponta, da ideia ao aplicativo executável.","order":10},"headers":[],"relativePath":"pt/hyz1992/agent-app-factory/start/index.md","filePath":"pt/hyz1992/agent-app-factory/start/index.md"}'),t={name:"pt/hyz1992/agent-app-factory/start/index.md"};function n(s,e,d,l,c,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="primeiros-passos" tabindex="-1">Primeiros Passos <a class="header-anchor" href="#primeiros-passos" aria-label="Permalink to &quot;Primeiros Passos&quot;">​</a></h1><p>Este capítulo ajuda você a começar rapidamente com o AI App Factory, entender o valor central, instalar e configurar as ferramentas, e compreender como funciona o pipeline de 7 estágios, preparando você para gerar seu primeiro aplicativo.</p><h2 id="caminho-de-aprendizagem" tabindex="-1">Caminho de Aprendizagem <a class="header-anchor" href="#caminho-de-aprendizagem" aria-label="Permalink to &quot;Caminho de Aprendizagem&quot;">​</a></h2><p>Recomenda-se seguir a ordem abaixo para estudar o conteúdo deste capítulo:</p><h3 id="_1-inicio-rapido-da-ideia-ao-aplicativo" tabindex="-1">1. <a href="./../getting-started/">Início Rápido: Da Ideia ao Aplicativo</a> <a class="header-anchor" href="#_1-inicio-rapido-da-ideia-ao-aplicativo" aria-label="Permalink to &quot;1. [Início Rápido: Da Ideia ao Aplicativo](../getting-started/)&quot;">​</a></h3><p>Entenda o valor central do AI App Factory e os pré-requisitos, experimentando o fluxo de ponta a ponta da ideia ao aplicativo através de um caso completo.</p><ul><li>Compreenda o mecanismo de colaboração multi-Agent baseado em checkpoints</li><li>Conheça o fluxo de trabalho completo do pipeline de 7 estágios</li><li>Domine as técnicas de fornecer descrições claras de produtos</li></ul><h3 id="_2-instalacao-e-configuracao" tabindex="-1">2. <a href="./../installation/">Instalação e Configuração</a> <a class="header-anchor" href="#_2-instalacao-e-configuracao" aria-label="Permalink to &quot;2. [Instalação e Configuração](../installation/)&quot;">​</a></h3><p>Instale a ferramenta CLI globalmente, configure o assistente de IA (Claude Code/OpenCode) e o ambiente relacionado.</p><ul><li>Instale o agent-app-factory globalmente usando npm</li><li>Configure o Claude Code ou OpenCode</li><li>Verifique se a instalação foi bem-sucedida</li></ul><h3 id="_3-inicializacao-do-projeto-factory" tabindex="-1">3. <a href="./../init-project/">Inicialização do Projeto Factory</a> <a class="header-anchor" href="#_3-inicializacao-do-projeto-factory" aria-label="Permalink to &quot;3. [Inicialização do Projeto Factory](../init-project/)&quot;">​</a></h3><p>Inicialize o diretório usando o comando <code>factory init</code>, entendendo a estrutura do projeto gerado e os arquivos de configuração.</p><ul><li>Execute o comando de inicialização do projeto</li><li>Compreenda a estrutura do diretório do projeto e arquivos de configuração</li><li>Prepare a entrada da ideia do produto</li></ul><h3 id="_4-visao-geral-do-pipeline-de-7-estagios" tabindex="-1">4. <a href="./../pipeline-overview/">Visão Geral do Pipeline de 7 Estágios</a> <a class="header-anchor" href="#_4-visao-geral-do-pipeline-de-7-estagios" aria-label="Permalink to &quot;4. [Visão Geral do Pipeline de 7 Estágios](../pipeline-overview/)&quot;">​</a></h3><p>Entenda profundamente o fluxo completo do pipeline, desde Bootstrap até Preview, as entradas e saídas de cada estágio e o mecanismo de checkpoint.</p><ul><li>Entenda os objetivos e produtos dos 7 estágios</li><li>Domine o mecanismo de checkpoint e o processo de confirmação manual</li><li>Aprenda como controlar a execução do pipeline</li></ul><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><p>Antes de começar a estudar este capítulo, você precisa:</p><div class="warning custom-block"><p class="custom-block-title">Requisitos Prévios</p><ol><li><strong>Ambiente Node.js</strong>: Node.js v18 ou superior instalado</li><li><strong>Assistente de Programação de IA</strong>: Deve configurar uma das ferramentas abaixo <ul><li><a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code</a> (Recomendado) ⭐</li><li><a href="https://opencode.design/" target="_blank" rel="noreferrer">OpenCode</a> ou outro assistente de IA que suporte modo Agent</li></ul></li><li><strong>Operações Básicas de Linha de Comando</strong>: Capacidade de usar o terminal para executar comandos</li></ol></div><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após completar o estudo deste capítulo, você dominará:</p><ul><li>✅ O princípio de funcionamento central do AI App Factory</li><li>✅ A instalação e configuração da ferramenta CLI</li><li>✅ A inicialização do projeto e compreensão da estrutura</li><li>✅ O fluxo completo do pipeline de 7 estágios</li></ul><p>Em seguida, recomenda-se estudar o capítulo <strong><a href="./../../platforms/">Plataformas e Integrações</a></strong>, para entender como executar o pipeline em diferentes assistentes de IA.</p>',23)])])}const f=a(t,[["render",n]]);export{m as __pageData,f as default};
